#!/usr/bin/env bash
# workflow-1.sh — 设计信奥赛训练计划 SOP walkthrough for 青少年编程教育.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="青少年编程教育"
WORKFLOW="设计信奥赛训练计划"

usage() {
  cat <<EOF
workflow-1.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./workflow-1.sh             # interactive
  ./workflow-1.sh --dry-run
  ./workflow-1.sh --json
  ./workflow-1.sh --explain
  ./workflow-1.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "设计信奥赛训练计划" 工作流。

一句话: 为决定参加 CSP/NOIP/NOI 竞赛路线的12-18岁学生制定12-24个月分阶段训练计划。

入门 SOP 共 6 步, 失败模式自检 0 项。

相关心智模型:
  • 制作即学习 (Making Is Learning): 编程教育的核心不是教「编程语言语法」, 而是让学生通过创造可分享的外部作品来建构内部知识 — Papert 的建构主义 (constructionism) 是整个领域的哲学根基
  • 低地板、高天花板、宽墙壁 (Low Floor, High Ceiling, Wide Walls): 好的编程教育工具必须同时满足三个维度 — 入门门槛低 (low floor, 6 岁能开始)、能力上限高 (high ceiling, 能做复杂项目)、创作方向广 (wide walls, 不限于一种

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "基线评估与目标校准: 用 Codeforces Div.3 或 Luogu P1000-P1500 级题目评估当前水平，设定12个月目标（CSP-J初赛入围 / CSP-S提高组 / NOIP参赛资格）；inputs: 学生基础，outputs: 评估报告+目标设定。"
  "绘制知识点图谱: 梳理竞赛知识体系——基础层（STL/排序/贪心/简单DP）→中级层（图论/高级DP/数学）→高级层（数据结构/字符串/计算几何）(evidence: [T03-S007])；inputs: 目标等级，outputs: 知识点依赖图。"
  "制定阶段性刷题计划: 每阶段2-3个月，设定每周刷题量（初期10题/周，竞赛前30题/周），平台以 Luogu + Codeforces + 洛谷题单为主 (evidence: [T03-S006])；inputs: 知识图谱，outputs: 周计划表格。"
  "加入模拟赛与比较训练: 每月至少1次模拟赛（USACO月赛、Codeforces Round、或自制模拟赛），赛后必须进行错题复盘；inputs: 刷题计划，outputs: 模拟赛日历+复盘模板。"
  "构建薄弱点补强机制: 建立\"错题本\"数据库（题目/知识点/错因/AC代码），每两周集中攻克高频错因知识点；inputs: 错题记录，outputs: 补强专项练习集。"
  "赛前6-8周冲刺: 停止新知识点学习，集中做历年真题+全真模拟，调整作息到与考试同步；inputs: 训练积累，outputs: 冲刺阶段方案。"
)
declare -a FAILURE_MODES=(

)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "workflow-1-walkthrough"
fi
